                        </Grid>
                        <Grid item xs={12} className="more-me">
                            <SmsBankingDialog />
                        </Grid>
                    </Grid>
                </Grid>
            </Dialog>

            <Dialog
                maxWidth="xl"
                fullWidth={true}
                open={open.payment}
                onClose={() => setOpen({ ...open, payment: false })}
                aria-labelledby="alert-dialog-title"
                aria-describedby="alert-dialog-description"
                TransitionComponent={Transition}
            >
                <Grid container>
                    <Grid item container xs={12}>
                        <Grid item xs={1}>
                        </Grid>
